// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Get admin dashboard overview
	// (GET /api/v1/admin/dashboard/overview)
	GetAdminDashboardOverview(ctx context.Context, request GetAdminDashboardOverviewRequestObject) (GetAdminDashboardOverviewResponseObject, error)
	// Get admin dashboard time series
	// (GET /api/v1/admin/dashboard/timeseries)
	GetAdminDashboardTimeseries(ctx context.Context, request GetAdminDashboardTimeseriesRequestObject) (GetAdminDashboardTimeseriesResponseObject, error)
	// Get instance statistics
	// (GET /api/v1/admin/stats)
	GetAdminStats(ctx context.Context, request GetAdminStatsRequestObject) (GetAdminStatsResponseObject, error)
	// List instance teams
	// (GET /api/v1/admin/teams)
	ListAdminTeams(ctx context.Context, request ListAdminTeamsRequestObject) (ListAdminTeamsResponseObject, error)
	// Get an instance team
	// (GET /api/v1/admin/teams/{id})
	GetAdminTeam(ctx context.Context, request GetAdminTeamRequestObject) (GetAdminTeamResponseObject, error)
	// List instance users
	// (GET /api/v1/admin/users)
	ListAdminUsers(ctx context.Context, request ListAdminUsersRequestObject) (ListAdminUsersResponseObject, error)
	// Delete an instance user
	// (DELETE /api/v1/admin/users/{id})
	DeleteAdminUser(ctx context.Context, request DeleteAdminUserRequestObject) (DeleteAdminUserResponseObject, error)
	// Get an instance user
	// (GET /api/v1/admin/users/{id})
	GetAdminUser(ctx context.Context, request GetAdminUserRequestObject) (GetAdminUserResponseObject, error)
	// Update an instance user
	// (PATCH /api/v1/admin/users/{id})
	UpdateAdminUser(ctx context.Context, request UpdateAdminUserRequestObject) (UpdateAdminUserResponseObject, error)
	// Reactivate a suspended user
	// (POST /api/v1/admin/users/{id}/reactivate)
	ReactivateAdminUser(ctx context.Context, request ReactivateAdminUserRequestObject) (ReactivateAdminUserResponseObject, error)
	// Suspend a user
	// (POST /api/v1/admin/users/{id}/suspend)
	SuspendAdminUser(ctx context.Context, request SuspendAdminUserRequestObject) (SuspendAdminUserResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

